-- The referenced table `tenants` is shared across tenants by definition,
-- so an FK to it does not need to carry `tenant_id`.
CREATE TABLE orders (
  id        bigserial PRIMARY KEY,
  tenant_id bigint NOT NULL REFERENCES tenants (id)
);

-- `audit_*` tables are excluded by `excludeTablePattern`, so a missing
-- `tenant_id` is not reported.
CREATE TABLE audit_events (
  id      bigserial PRIMARY KEY,
  user_id bigint REFERENCES users (id)
);

-- No FK constraints — nothing to flag.
CREATE TABLE orders (
  id        bigserial PRIMARY KEY,
  tenant_id bigint NOT NULL,
  amount    numeric(10, 2)
);
